def require_valid_token(f):
    """Decorator that validates JWT tokens properly before forwarding requests."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get("Authorization")

        if not auth_header:
            return jsonify({"error": "Missing Authorization header"}), 401

        parts = auth_header.split()
        if len(parts) != 2 or parts[0].lower() != "bearer":
            return jsonify({"error": "Invalid Authorization header format. Use: Bearer <token>"}), 401

        token = parts[1]

        try:
            # SECURE token verification with signature validation
            decode_options = {
                "verify_signature": True,  # NEVER set this to False in any environment
                "verify_exp": True,
                "verify_nbf": True,
                "verify_iat": True,
                "require": ["exp", "iat", "sub"],
            }

            decode_kwargs = {
                "algorithms": [JWT_ALGORITHM],
                "options": decode_options,
            }

            # Use public key for asymmetric algorithms, secret for symmetric
            if JWT_ALGORITHM.startswith("RS") or JWT_ALGORITHM.startswith("ES"):
                JWT_PUBLIC_KEY = open(os.environ.get("JWT_PUBLIC_KEY_PATH", "public.pem")).read()
                decode_kwargs["key"] = JWT_PUBLIC_KEY
            else:
                if not JWT_SECRET:
                    app.logger.error("JWT_SECRET environment variable is not set!")
                    return jsonify({"error": "Server configuration error"}), 500
                decode_kwargs["key"] = JWT_SECRET

            if JWT_ISSUER:
                decode_kwargs["issuer"] = JWT_ISSUER
            if JWT_AUDIENCE:
                decode_kwargs["audience"] = JWT_AUDIENCE

            claims = jwt.decode(token, **decode_kwargs)

            # Store validated claims for use in route handlers
            g.jwt_claims = claims
            g.user_id = claims.get("sub")
            g.user_roles = claims.get("roles", [])
            g.user_email = claims.get("email")
            g.raw_token = token

        except ExpiredSignatureError:
            return jsonify({"error": "Token has expired"}), 401
        except InvalidSignatureError:
            app.logger.warning(f"Invalid token signature from IP: {request.remote_addr}")
            return jsonify({"error": "Invalid token signature"}), 401
        except DecodeError:
            return jsonify({"error": "Token could not be decoded"}), 401
        except InvalidTokenError as e:
            app.logger.warning(f"Invalid token from IP: {request.remote_addr}: {str(e)}")
            return jsonify({"error": "Invalid token"}), 401

        return f(*args, **kwargs)

    return decorated_function


def require_roles(*required_roles):
    """Decorator to check if user has required roles after token validation."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            user_roles = set(g.get("user_roles", []))
            if not user_roles.intersection(set(required_roles)):
                return jsonify({"error": "Insufficient permissions"}), 403
            return f(*args, **kwargs)
        return decorated_function
    return decorator


def forward_to_backend(service_path, method="GET", data=None):
    """Forward request to backend service with validated user claims as headers."""
    backend_url = f"{BACKEND_BASE_URL}{service_path}"

    # Forward validated claims as trusted internal headers
    headers = {
        "X-User-Id": str(g.user_id) if g.user_id else "",
        "X-User-Email": str(g.user_email) if g.user_email else "",
        "X-User-Roles": ",".join(g.user_roles) if g.user_roles else "",
        "X-Request-Forwarded-By": "api-gateway",
        "Content-Type": request.content_type or "application/json",
    }

    # Optionally forward the original token for service-to-service auth
    # headers["Authorization"] = f"Bearer {g.raw_token}"

    try:
        if method.upper() == "GET":
            resp = requests.get(backend_url, headers=headers, params=request.args, timeout=30)
        elif method.upper() == "POST":
            resp = requests.post(backend_url, headers=headers, json=data or request.get_json(silent=True), timeout=30)
        elif method.upper() == "PUT":
            resp = requests.put(backend_url, headers=headers, json=data or request.get_json(silent=True), timeout=30)
        elif method.upper() == "DELETE":
            resp = requests.delete(backend_url, headers=headers, timeout=30)
        elif method.upper() == "PATCH":
            resp = requests.patch(backend_url, headers=headers, json=data or request.get_json(silent=True), timeout=30)
        else:
            return jsonify({"error": f"Unsupported method: {method}"}), 405

        # Return the backend response to the client
        return (resp.content, resp.status_code, dict(resp.headers))

    except requests.exceptions.ConnectionError:
        app.logger.error(f"Backend service unreachable: {backend_url}")
        return jsonify({"error": "Backend service unavailable"}), 503
    except requests.exceptions.Timeout:
        return jsonify({"error": "Backend service timeout"}), 504
    except requests.exceptions.RequestException as e:
        app.logger.error(f"Backend request failed: {str(e)}")
        return jsonify({"error": "Internal gateway error"}), 500


