@app.route("/api/users/<user_id>", methods=["GET", "PUT", "DELETE"])
@require_valid_token
def proxy_user(user_id):
    """Forward to user service - users can access their own data, admins can access any."""
    if str(g.user_id) != str(user_id) and "admin" not in g.user_roles:
        return jsonify({"error": "You can only access your own data"}), 403
    return forward_to_backend(f"/users/{user_id}", method=request.method)


